function makePage(brief: RapidBrief): SeoPage {
  const cards = brief.group === 'database' ? mapHub : brief.group === 'tools' || brief.group === 'news' ? platformHub : brief.topic.toLowerCase().includes('class') || brief.topic.match(/Mercenary|Sorcerer|Blackarrow|Shadowstrix|Seer|Withered/) ? classHub : systemHub;
  return {
    slug: brief.slug,
    group: brief.group,
    template: brief.template,
    title: brief.title,
    description: brief.description,
    eyebrow: brief.template === 'map' ? 'Map route' : brief.template === 'build' ? 'Build guide' : brief.template === 'faq' ? 'Tracker' : 'Long-tail guide',
    h1: brief.topic,
    lead: `This page targets players searching for ${brief.topic}. It focuses on ${brief.angle} while clearly marking what still needs launch-build verification.`,
    intent: {
      primary: `Mistfall Hunter ${brief.topic}`,
      secondary: brief.related,
      freshness: brief.update,
    },
    checklist: [
      `Use this page for ${brief.audience}`,
      `Focus on ${brief.angle}`,
      `Avoid ${brief.risk}`,
      'Prefer extracted value over extended greed',
      'Replace assumptions with verified launch data when available',
    ],
    steps: [
      { title: 'Define the run goal', body: `Before entering the Gyldenmist, decide whether this page is being used for learning, loot, PvP, boss prep, or troubleshooting.` },
      { title: 'Apply the safe rule', body: `The safe rule for this topic is simple: ${brief.angle}. If the run stops supporting that goal, rotate or extract.` },
      { title: 'Record what changes', body: `After launch, update this page with screenshots, exact values, menu names, map markers, and patch changes instead of guessing.` },
    ],
    tables: [{
      title: `${brief.topic} decision table`,
      headers: ['Situation', 'Recommended answer', 'Why it matters'],
      rows: [
        ['First time learning', `Use cheap gear and test ${brief.topic} in low-risk routes`, 'Information is more valuable than one lucky run'],
        ['You already have useful loot', 'Move toward extraction instead of adding another objective', 'Banked value is the real win condition'],
        ['A fight gets loud or long', 'Reset, listen, and assume another player heard it', 'Third parties punish slow decisions'],
        ['A detail is not yet verified', 'Mark it as pending and update after launch verification', 'Trust matters more than fake precision'],
      ],
    }],
    sections: [
      { heading: 'Why this URL deserves to exist', body: [`${brief.topic} is a specific search intent, not a generic article. Players reaching this page want a focused answer for ${brief.audience}, so the content is organized around decisions, risk, and update targets.`] },
      { heading: 'Current best answer', body: [`The practical answer is to ${brief.angle}. This keeps the page useful before final numbers are public and gives a clear path for adding verified screenshots, values, and examples later.`] },
      { heading: 'What not to overclaim', body: [`Do not invent exact drop rates, cooldowns, map pins, or tier rankings for this topic until they are confirmed. The main risk to avoid is ${brief.risk}.`] },
    ],
    cards,
    relatedSearches: [`Mistfall Hunter ${brief.topic}`, ...brief.related],
    faqs: [
      { q: `Is this ${brief.topic} page based on confirmed data?`, a: 'It uses confirmed public game concepts and cautious extraction-game guidance. Exact values, markers, and rankings should be updated after launch verification.' },
      { q: `Who should use this ${brief.topic} guide?`, a: `It is designed for ${brief.audience}.` },
      { q: 'Why not list exact numbers now?', a: 'Publishing invented numbers creates low-quality pages. This URL is structured so exact data can be added quickly once it is verified.' },
    ],
    sources: [
      { href: 'https://www.mistfallhunter.com/', label: 'Mistfall Hunter official site' },
      { href: 'https://store.steampowered.com/app/3282300/Mistfall_Hunter/', label: 'Mistfall Hunter on Steam' },
    ],
    confidence: 'reported',
  };
}

function localizeDraft(page: SeoPage): SeoPage {
  return {
    ...page,
    draft: true,
    title: `${page.title} | Chinese Draft`,
    description: `${page.description} Chinese draft URL reserved for later localization with verified launch data.`,
    eyebrow: `ZH ${page.eyebrow}`,
    h1: `${page.h1} Chinese guide`,
    lead: `${page.lead} This Chinese URL is intentionally deployment-safe and can be localized in a later copy pass.`,
    cards: page.cards?.map((card) => ({ ...card, href: card.href.startsWith('/zh/') ? card.href : `/zh${card.href}` })),
    intent: page.intent ? { ...page.intent, primary: `${page.intent.primary} Chinese`, freshness: 'Localize after launch with verified screenshots, values, patch notes, and Chinese search wording.' } : undefined,
    sections: [
      { heading: 'Chinese draft status', body: ['This URL reserves the same long-tail search target for the Chinese site while avoiding unverified claims and encoding risk in the current rapid expansion pass.'] },
      ...(page.sections ?? []),
    ],
    relatedSearches: page.relatedSearches?.map((item) => `${item} Chinese`),
  };
}

export const enRapidExpansionPages: SeoPage[] = briefs.map(makePage);
export const zhRapidExpansionPages: SeoPage[] = enRapidExpansionPages.map(localizeDraft);

export const enRapidExpansionLinks: PriorityLink[] = enRapidExpansionPages.map((page) => ({
  title: page.h1,
  desc: page.description,
  href: `/${page.slug}`,
  group: page.group,
}));

export const zhRapidExpansionLinks: PriorityLink[] = zhRapidExpansionPages.map((page) => ({
  title: page.h1,
  desc: page.description,
  href: `/zh/${page.slug}`,
  group: page.group,
}));
